var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그러니까...... 자네들 이름이 릴리와 리코리스라고 했던가?","JPN":"それで……名前はリリーとリコリスと言ったか？","ENG":"Hmm... So your names are Lily and Lycoris?","TWN":"所以……你們叫莉莉和莉克麗絲對嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그렇습니다, 교수님.","JPN":"はい、教授。","ENG":"Yes, Professor.","TWN":"是的，教授。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>맨션</color>의 취향은 듣던 대로 꽤나 고상하군. 기르는 사냥개들에게 꽃 이름을 붙여 주다니.","JPN":"<color=#ffd34c>マンション</color>の好みは噂通りお上品だな。飼い犬に花の名前を付けるなんて。","ENG":"The <color=#ffd34c>Mansion</color> seems to have a most sophisticated taste as its reputation says. Naming its hounds after flowers...","TWN":"<color=#ffd34c>曼森</color>的品味如傳聞一樣高尚。竟然給飼養的獵犬取花的名字。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"잔소리 그만하고 안내나 하지 그래?","JPN":"無駄話はそれくらいにしてさっさと案内して。","ENG":"Alright, enough small talk. Why don't you just show us the way?","TWN":"廢話少說，趕緊帶路。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"우린 당신이랑 노닥거리러 온 거 아니거든?","JPN":"私はあんたと仲良くおしゃべりしに来たわけじゃないの。","ENG":"We're not here to goof around with you.","TWN":"我們可不是來和你閒聊的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"흠. 누가 젊은 친구들 아니랄까 봐 열정이 넘치는군.","JPN":"ほう。さすが若者はやる気満々でいいな。","ENG":"Hah. Young and passionate, I see.","TWN":"唔。果然是年輕人啊，血氣方剛的。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"거의 다 왔네. 조금만 더 참게나.","JPN":"あと少しで着くからあせる必要はない。","ENG":"We're almost there. Have a little patience.","TWN":"快到了，再堅持一下。"},"stage":{"bg":"CITY_STREET_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"자, 여길세. 데몬 타입 침식체가 출몰했던 침식 재난 구역의 한복판이지.","JPN":"さあ、ここだ。デーモンタイプ侵食体が出没した侵食災害区域の中心だ。","ENG":"Here we are. We're in the middle of the disaster zone where the Demon-Type C.O.s appeared.","TWN":"到了，這裡就是惡魔型侵蝕體出沒的侵蝕災難區域的中心。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"재난이 터졌을 때 소유주가 사망하는 바람에 행정상으로 유령처럼 붕 뜬 곳이 됐어.","JPN":"災害が起きた時に所有者が死亡して、行政上の都合で今は空き地同然なのさ。","ENG":"The owner was killed during the incident, so this place is an administrative no-man's land.","TWN":"災難來臨的時候業主死了，這裡就成了幽靈城市。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"용병들이 기웃거릴 일도 드물 테니 아지트로 안성맞춤일 걸세.","JPN":"傭兵が来ることもめったにないと思うから、アジトとしてはうってつけの場所だろう。","ENG":"Even mercenaries stay away from here. It will be a perfect hideout for you.","TWN":"傭兵也不會來這裡，所以最適合做秘密基地了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"흥, 돈 받고 이딴 폐허를 소개해 주는 거야?","JPN":"ふん、人からもらった金でこんな廃墟を紹介するの？","ENG":"Hmpf. This is what we get for what we're paying you?","TWN":"哼，你收了錢就給我們介紹這種破地方？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"블랙 네트워크에서 솜씨 좋은 중계상이라고 하던데 별거 없네.","JPN":"ブラックネットワークで腕のいい仲介人と聞いたのに、大したことないわね。","ENG":"I heard you were one of the best brokers on the Dark Network, but I guess your reputation's exaggerated.","TWN":"什麼黑色網路裡有名的仲介商，我看也不過如此而已。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"리코리스. 불평 그만하고 저 분께 남은 대금을 넘겨 드리세요.","JPN":"リコリス、文句をいうのはそれくらいにして、その方に残金を支払ってください。","ENG":"Lycoris, stop complaining and issue him the remainder of the payment.","TWN":"莉克麗絲，別抱怨了，趕緊把剩下的錢給他吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"뭐? 너 정말 여기서 지낼 생각이야?","JPN":"え？　リリーは本当にここでいいの？","ENG":"What? Are you seriously thinking of staying here?","TWN":"什麼？妳真的要選這裡？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"우리는 비합법적인 경로로 이 도시에 숨어들어 온 입장이에요.","JPN":"私たちは非合法のルートでこの都市に入った立場です。","ENG":"We snuck into this city through an illegal route.","TWN":"我們是通過非法途徑偷偷來到這個城市的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"눈에 띄는 숙소에서 지내다가 귀찮은 일을 만들면 마스터를 뵐 면목이 없습니다.","JPN":"人目の多い宿に泊まって面倒なことに巻き込まれたら、マスターに合わせる顔がないでしょう。","ENG":"We don't want to attract more attention than needed. What would the Master say?","TWN":"總不能住在顯眼的地方吧，萬一發生什麼麻煩事，我就沒臉見頭目了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"씨이......","JPN":"ちっ……","ENG":"Ugh...","TWN":"切……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"나야 돈가방에는 큰 미련이 없네.","JPN":"わしは金にそこまで興味はない。","ENG":"I have little need for money, if you'd rather hold on to the rest.","TWN":"並不一定要付錢。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"원한다면 정보로 계산을 대신할 수도 있지.","JPN":"望むなら代金のかわりに情報で支払ってもらっても構わないぞ。","ENG":"If you'd like, you could pay me with information instead.","TWN":"如果可以的話，你們可以用情報代替。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"무슨 말씀이시죠?","JPN":"それはどういう意味ですか？","ENG":"What do you mean?","TWN":"什麼意思？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"내가 강단에 오르는 건 지식에 대한 갈망 때문이라네.","JPN":"わしが教壇に立つ理由は一つ、知識への渇望のためだ。","ENG":"The reason I take to the lectern is because of my thirst for knowledge.","TWN":"我從事教育工作，是因為我渴望知識。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"학생들의 질문을 받으면서 때때로 내가 뭘 몰랐는지 알아챌 수 있거든.","JPN":"学生から質問を受けることで、わしが何を知らないのか気付くことができるのさ。","ENG":"My students' questions sometimes help me realize what I have yet to learn.","TWN":"通過學生的提問，有時我可以察覺到一些我不懂的東西。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"미지의 영역을 알아차리고, 이해해 나가는 건 무척 황홀한 과정이야.","JPN":"未知の領域を認識、理解していくことはとても素晴らしい過程さ。","ENG":"Identifying what I do not know and gaining new knowledge in those areas is so exhilarating.","TWN":"探索未知的領域，繼而理解的這個過程，是非常妙不可言的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그러니 어떤가. 맨션에 대해 얘기해 주는 건.","JPN":"それで、どうかね。マンションについて話してくれるのは。","ENG":"So... how about you tell me more about the Mansion?","TWN":"所以，告訴我一下曼森的事情吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"듣자 하니 요즘 작은 소란이 있었다던데.","JPN":"風の噂によると、この頃ちょっとした騒ぎがあったようだが。","ENG":"I've heard there was a little scuffle there recently.","TWN":"聽說最近有過一場小騷亂。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"뭐? 당신 지금 뭐라고 했어?","JPN":"はあ？　あんた今なんて言ったの？","ENG":"What? What did you just say?","TWN":"什麼？你剛剛說什麼？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"하하. 대단한 얘기를 듣겠다는 건 아닐세.","JPN":"ハハハ。詳しい事情が聞きたいわけではない。","ENG":"Hah hah. I'm not asking you to reveal some grand secret or anything.","TWN":"哈哈，我並不是想要什麼重要的情報。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"나는 그저 내가 조사한 내용이 맞는지 검증하고 싶을 뿐이야.","JPN":"わしはただ、自分が調べた内容が合っているのか確かめたいだけでな。","ENG":"I simply wish to verify whether the findings of my investigation bear any truth.","TWN":"我只是想驗證一下，我調查的內容是否屬實。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"마스터의 허락 없이는 맨션에 심어진 관목 한 그루에 대해서도 말씀드릴 수 없습니다.","JPN":"マスターの許可なしでは、マンションの庭に植えられた木一本のことすら、申し上げることはできません。","ENG":"Without the Master's express approval, we cannot tell you about a single shrub planted in the Mansion courtyard.","TWN":"沒有頭目的允許，哪怕是種植在曼森的一棵灌木，我也不會告訴你。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그러니 호기심은 접어 주시죠.","JPN":"ですから、その好奇心は心の中に閉まっておいてください。","ENG":"So please put your curiosity to rest.","TWN":"所以，你還是收起你的好奇心吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"그것 참 섭섭한 대답이군.","JPN":"それは残念な答えだな。","ENG":"How disappointing.","TWN":"真是可惜了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"하지만 소득이 전혀 없는 건 아니라서 다행이야.","JPN":"でも全く収穫がないわけではない。","ENG":"Still, at least I learned something after all.","TWN":"不過，也不是一無所獲。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"적어도 맨션에 관목이 심어져 있다는 것 정도는 알게 됐으니까.","JPN":"少なくとも、マンションに木が植えられていることくらいはわかったからな。","ENG":"Now I know you have shrubs around the Mansion.","TWN":"至少我知道曼森家裡有種了灌木。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"늦든 빠르든 맨션에 대해선 더 알 기회가 생기겠지. 관광이나 하자고 이 먼 곳까지 오진 않았을 테니까.","JPN":"遅かれ早かれマンションについては知る機会があるだろう。君たちがこんなに遠い所まで、観光のために来るとは思えないからな。","ENG":"I'm sure the opportunity to learn more about the Mansion will present itself soon. I presume you didn't come all the way here on vacation.","TWN":"會有機會進一步瞭解曼森的，不過是早晚的問題。你們遠道而來，不可能是來旅遊的吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"대금은 받지 않겠네. 주문했던 탄약과 폭발물은 뒤뜰에 묻어 뒀으니 찾아 보게.","JPN":"代金はいい。注文の弾薬と爆弾の材料は裏庭に埋めておいたから探すといい。","ENG":"Don't worry about the remainder of the payment. You'll find the ammunition and explosives you ordered buried in the backyard.","TWN":"錢我就不要了。你們訂的彈藥和炸彈埋在後院了，你們自己去找吧。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"사양하지 않겠습니다. 살펴 가시길.","JPN":"遠慮なくいただきます。お気を付けて。","ENG":"Thanks for your favor. Farewell.","TWN":"那我就不客氣了，慢走。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"저 할아버진 뭐래. 중계나 해 주는 주제에 무게 잡긴.","JPN":"あのじじいは何者なの？　仲介人のくせに匂わせやがって。","ENG":"What was with that old fool? Acting like some kind of a big shot when he's nothing but a middleman.","TWN":"那老頭子說什麼呢？不就是個仲介嗎，裝什麼。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"신경 끄세요, 리코리스.","JPN":"気にすることありません、リコリス。","ENG":"Don't mind him, Lycoris.","TWN":"行了，莉克麗絲。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"지나친 호기심은 화를 부릅니다. 제가 당신 요리를 시식했을 때처럼요.","JPN":"過ぎた好奇心は災いを招きます。私があなたの料理を試食した時のように。","ENG":"Curiosity killed the cat. Just like when I tried your cooking.","TWN":"好奇害死貓，就像我試吃你做的料理的時候。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"누, 누가 너더러 먹으래? 자기가 맘대로 집어 먹어 놓고서!","JPN":"そ、それはリリーが勝手に食べたせいでしょ！　別に食べさせるつもりはなかったし！","ENG":"I-I never said you had to try it! That's on you!","TWN":"誰、誰逼妳吃了？還不是妳自己要吃的！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"아무튼 그래서 이제 어쩔 거야?","JPN":"で、これからどうするの？","ENG":"So what now?","TWN":"所以，接下來要怎麼做？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"우리가 맨션에서 받은 정보라곤 타깃이 그라운드 원으로 떠났다는 것뿐이잖아.","JPN":"マンションからもらった手がかりは、ターゲットがグラウンド・ワンに行ったってことだけでしょ。","ENG":"The only intel we have from the Mansion is that the target is headed towards Ground One.","TWN":"我們從曼森只收到了目標離開了G1的情報。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"사막에서 바늘 찾기지, 이게 무슨......","JPN":"砂漠の中で針を探すようなものだよ。どうやって……","ENG":"Might as well as find a needle in a haystack...","TWN":"這不是海底撈針嗎……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"마스터께선 그런 상황을 의도하시고 제게 심부름을 맡기셨을지도 모르죠.","JPN":"マスターはこのような状況を想定して私にこの仕事を任せてくださったのだと思います。","ENG":"Perhaps the Master saw that coming and put me to the task for that very reason.","TWN":"也許頭目就是故意給我安排這件事的。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"제 추측이 맞다면, 이번 심부름 결과에 따라 저에 대한 평가를 다시 내려 주실 겁니다.","JPN":"私の推測が正しければ、今回の仕事の結果次第で私に対する評価を見直してくださるでしょう。","ENG":"If my guess is right, she will come to see me in a different light, depending upon the outcome of this task.","TWN":"如果我的推測沒錯的話，透過這次辦事的結果，會對我重新進行評價。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"뭐야. 결국 타깃이랑 싸잡혀서 욕 먹기 싫어 가지고 그렇게 열심이었어?","JPN":"なんだ。結局ターゲットと一緒にされたくないからそんなに一生懸命だったの？","ENG":"So you're working your butt off just because you don't want to be treated like the target?","TWN":"什麼？原來妳是不想和目標一起被罵，所以才這麼認真？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"함부로 그 여자를 들먹이지 마세요. 뜬눈으로 흙 속에 파묻히기 싫으면.","JPN":"明日の朝棺桶の中で目覚めたくないなら、勝手にあの女と一緒にしないでください。","ENG":"Tread carefully when you compare me with that woman... if you don't want to be buried alive.","TWN":"你不要隨便說那個女人，如果你不想被活埋的話。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그럼 탐문을 시작하죠, 리코리스.","JPN":"では聞き込み調査を始めましょう、リコリス。","ENG":"Let's begin the search then, Lycoris.","TWN":"那我們開始打探一下吧，莉克麗絲。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"블랙 네트워크에서 구한 정보를 토대로, 도시관리국의 이목을 끌지 않게.","JPN":"ブラックネットワークから入手した情報をもとに、都市管理局に目を付けられないよう注意する必要があります。","ENG":"We'll leverage the intel from the Dark Network... and make sure we don't attract any attention from the City Management.","TWN":"利用在黑色網路蒐集到的情報，不要引起城市管理局的注意。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"......반드시, 그 여자를 찾아야 합니다.","JPN":"……必ず、あの女を見つけ出さなければなりません。","ENG":"We must find her.","TWN":"……我們必須，找到那個女人。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}}]`);export{e as default};